def longest_subsequence_sum(nums, target):
    # Initialize a DP array where dp[i] represents the maximum length of subsequence
    # that sums to 'i'. Initialize all values to -1 (indicating unreachable)
    dp = [-1] * (target + 1)
    dp[0] = 0  # Base case: empty subsequence sums to 0 with length 0

    for num in nums:
        # Iterate backwards to avoid overwriting values that are yet to be processed
        for i in range(target, num - 1, -1):
            if dp[i - num] != -1:
                if dp[i] < dp[i - num] + 1:
                    dp[i] = dp[i - num] + 1

    return dp[target]
